/// \file
/// This file declares the targeting of the RegisterBankInfo class for Xtensa.
/// \todo This should be generated by TableGen.
//===----------------------------------------------------------------------===//

#ifndef LLVM_LIB_TARGET_XTENSA_XTENSAREGISTERBANKINFO_H
#define LLVM_LIB_TARGET_XTENSA_XTENSAREGISTERBANKINFO_H

#include "llvm/CodeGen/GlobalISel/RegisterBankInfo.h"

#define GET_REGBANK_DECLARATIONS
#include "XtensaGenRegisterBank.inc"

namespace llvm {

class TargetRegisterInfo;

class XtensaGenRegisterBankInfo : public RegisterBankInfo {
protected:
  enum PartialMappingIdx {
    PMI_None = -1,
    PMI_BR = 1,
    PMI_AR,
    PMI_FPR,
    PMI_FirstBR = PMI_BR,
    PMI_LastBR = PMI_BR,
    PMI_FirstAR = PMI_AR,
    PMI_LastAR = PMI_AR,
    PMI_FirstFPR = PMI_FPR,
    PMI_LastFPR = PMI_FPR,
    PMI_Min = PMI_FirstFPR,
  };

 static RegisterBankInfo::PartialMapping PartMappings[];
 static RegisterBankInfo::ValueMapping ValMappings[];
 static PartialMappingIdx BankIDToCopyMapIdx[]; 


   /// Get the pointer to the ValueMapping of the operands of a copy
  /// instruction from the \p SrcBankID register bank to the \p DstBankID
  /// register bank with a size of \p Size.
  static const RegisterBankInfo::ValueMapping *
  getCopyMapping(unsigned DstBankID, unsigned SrcBankID, unsigned Size); 

#define GET_TARGET_REGBANK_CLASS
#include "XtensaGenRegisterBank.inc"
};

/// This class provides the information for the target register banks.
class XtensaRegisterBankInfo final : public XtensaGenRegisterBankInfo {
public:
  XtensaRegisterBankInfo(const TargetRegisterInfo &TRI);

  const RegisterBank &getRegBankFromRegClass(const TargetRegisterClass &RC,
                                             LLT) const override;

  InstructionMappings
  getInstrAlternativeMappings(const MachineInstr &MI) const override;

  const InstructionMapping &
  getInstrMapping(const MachineInstr &MI) const override;

  /// Here we have to narrowScalar s64 operands to s32, combine away G_MERGE or
  /// G_UNMERGE and erase instructions that became dead in the process. We
  /// manually assign bank to def operand of all new instructions that were
  /// created in the process since they will not end up in RegBankSelect loop.
  void applyMappingImpl(const OperandsMapper &OpdMapper) const override;

  /// RegBankSelect determined that s64 operand is better to be split into two
  /// s32 operands in gprb. Here we manually set register banks of def operands
  /// of newly created instructions since they will not get regbankselected.
  void setRegBank(MachineInstr &MI, MachineRegisterInfo &MRI) const;

private:
  
};
} // end namespace llvm
#endif
